def histogram(test):
    """Given a string representing a space separated lowercase letters, return a dictionary
    of the letter with the least repetition and containing the corresponding count.
    If several letters have the minimum occurrence, return only the first one found.

    Example:
    histogram('a b c') == {'a': 1}
